const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const agent_id = body.agent_id || null;
const client_id = body.client_id || null;
const activity_type = body.activity_type || null;
const duration = body.duration_minutes != null ? Number(body.duration_minutes) : null;
const metadata = body.metadata || {};
const client_token = body.client_token || null;

if (!agent_id || !activity_type) {
  return { json: { _error: true, error: 'agent_id + activity_type required', ok: false } };
}
if (!client_token) {
  return { json: { _error: true, error: 'client_token required', ok: false } };
}

return { json: { agent_id, client_id, activity_type, duration, metadata, client_token } };

const arr = $input.item.json || [];
const row = Array.isArray(arr) && arr.length > 0 ? arr[0] : null;
const parsed = $('Validate Input').first().json;
if (!row) return { json: { _skip: true, consent: false, reason: 'agent not found', ok: true, activity_id: null } };
if (!row.productivity_tracking_consent) return { json: { _skip: true, consent: false, reason: 'consent not granted', ok: true, activity_id: null } };
return { json: Object.assign({}, parsed, { client_id: parsed.client_id || row.client_id, _consent: true }) };

const fromRpc = $input.item.json;
const skip = $('Gate By Consent').first().json;
if (skip && skip._skip) {
  return { json: { ok: true, consent: false, activity_id: null, reason: skip.reason || 'consent not granted' } };
}
let activity_id = null;
if (typeof fromRpc === 'string') activity_id = fromRpc;
else if (fromRpc && fromRpc.id) activity_id = fromRpc.id;
else if (Array.isArray(fromRpc) && fromRpc.length > 0 && fromRpc[0].record_agent_activity) activity_id = fromRpc[0].record_agent_activity;
return { json: { ok: activity_id != null, consent: true, activity_id } };
